import { readFileSync, writeFileSync, mkdirSync } from "node:fs";

mkdirSync("dist", { recursive: true });

const src = readFileSync("src/cli.ts", "utf-8");

// Strip the type annotation (there are none complex enough to need a real compiler)
// and inject the build timestamp
const timestamp = new Date().toISOString();
const out = src.replace("__BUILD_TIMESTAMP__", timestamp);

writeFileSync("dist/cli.js", out);
console.log(`Built dist/cli.js (timestamp: ${timestamp})`);

